// ETAPA 3 - Adaptador de integracion
// Responsabilidad unica: preparar payload para el sistema externo
// Sin logica de negocio - solo transformacion de contrato

const input = $input.item.json;
const e3_start = new Date().toISOString();

// Idempotencia: generar clave unica para evitar duplicados en reintentos
const idempotency_key = `${input.run_id}-ticket`;

const ticketPayload = {
  idempotency_key,
  user_id: input.payload.user_id,
  session_id: input.payload.session_id || null,
  mensaje: input.payload.message,
  categoria: input.categoria,
  prioridad: input.prioridad,
  requiere_escalacion: input.requiereEscalacion,
  timestamp: input.start_ts,
  run_id: input.run_id
};

return [{
  json: {
    ...input,
    e3_start,
    ticketPayload,
    idempotency_key,
    retry_count: 0,
    max_retries: 3
  }
}];

const input = $('E3 - Preparar payload adaptador').item.json;
const httpResponse = $input.item.json;
const e3_end = new Date().toISOString();
const duracion_ms = new Date(e3_end) - new Date(input.e3_start);

console.log(JSON.stringify({
  run_id: input.run_id,
  etapa: 'E3_adaptador',
  status: 'ok',
  idempotency_key: input.idempotency_key,
  ticket_id: httpResponse.id || null,
  e3_start: input.e3_start,
  e3_end,
  duracion_ms
}));

return [{
  json: {
    run_id: input.run_id,
    start_ts: input.start_ts,
    categoria: input.categoria,
    prioridad: input.prioridad,
    respuesta: input.respuesta,
    ticket_id: httpResponse.id || null,
    payload: input.payload
  }
}];
